import React, { useState } from 'react';
import axios from 'axios';
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  const [form, setForm] = useState({
    StudentID: 1000000,
    CGPA: 7.5,
    Internships: 1,
    Projects: 10,
    'Workshops/Certifications': 10,
    AptitudeTestScore: 85,
    SoftSkillsRating: 4.4,
    ExtracurricularActivities: 0,
    PlacementTraining: 0,
    SSC_Marks: 65,
    HSC_Marks: 79
  });

  const [prediction, setPrediction] = useState(null);

  const handleChange = e => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: parseFloat(value) });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:5000/predict', form);
      setPrediction(res.data);
    } catch (error) {
      console.error("Error while fetching prediction", error);
    }
  };

  const formStyle = {
    display: 'flex',
    flexDirection: 'column',
    maxWidth: '400px',
    gap: '10px',
    backgroundColor: '#003366',
    padding: '20px',
    borderRadius: '10px',
    boxShadow: '0 0 10px rgba(0,0,0,0.1)',
    marginTop: '20px',
    color: 'white'
  };

  const inputStyle = {
    padding: '8px',
    fontSize: '16px',
    borderRadius: '4px',
    border: '1px solid #ccc',
    backgroundColor: '#00509e',
    color: 'white'
  };

  const labelStyle = {
    marginBottom: '4px',
    fontWeight: '600',
    color: 'white'
  };

  const resultBoxStyle = {
    marginTop: '20px',
    padding: '15px',
    border: '2px solid #ccc',
    borderRadius: '8px',
    width: '300px',
    textAlign: 'center',
    fontSize: '18px',
    fontWeight: 'bold',
    backgroundColor: '#e0ffe0',
    color: '#006400',
    display: 'inline-block'
  };

  const sadResultBoxStyle = {
    ...resultBoxStyle,
    backgroundColor: '#ffe0e0',
    color: '#8b0000'
  };

  const containerStyle = {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    gap: '20px',
    marginTop: '20px'
  };

  return (
    <div style={{ padding: "2rem" }}>
      {/* Bootstrap Navbar */}
      <nav className="navbar navbar-expand-lg navbar-light bg-light">
        <a className="navbar-brand" href="#">Navbar</a>
        <button className="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarSupportedContent"
          aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>

        <div className="collapse navbar-collapse" id="navbarSupportedContent">
          <ul className="navbar-nav mr-auto">
            <li className="nav-item active">
              <a className="nav-link" href="#">Home <span className="sr-only">(current)</span></a>
            </li>
            <li className="nav-item">
              <a className="nav-link" href="#">Link</a>
            </li>
            <li className="nav-item dropdown">
              <a className="nav-link dropdown-toggle" href="#" id="navbarDropdown" role="button" data-toggle="dropdown"
                aria-haspopup="true" aria-expanded="false">
                Dropdown
              </a>
              <div className="dropdown-menu" aria-labelledby="navbarDropdown">
                <a className="dropdown-item" href="#">Action</a>
                <a className="dropdown-item" href="#">Another action</a>
                <div className="dropdown-divider"></div>
                <a className="dropdown-item" href="#">Something else here</a>
              </div>
            </li>
            <li className="nav-item">
              <a className="nav-link disabled" href="#">Disabled</a>
            </li>
          </ul>
          <form className="form-inline my-2 my-lg-0">
            <input className="form-control mr-sm-2" type="search" placeholder="Search" aria-label="Search" />
            <button className="btn btn-outline-success my-2 my-sm-0" type="submit">Search</button>
          </form>
        </div>
      </nav>

      {/* Marquee (Optional) */}
      <div style={{
        backgroundColor: '#f0f0f0',
        color: '#333',
        padding: '10px 0',
        fontWeight: 'bold',
        fontSize: '18px',
        marginTop: '5px',
        overflow: 'hidden',
        whiteSpace: 'nowrap'
      }}>
        <div style={{
          display: 'inline-block',
          paddingLeft: '100%',
          animation: 'marquee 15s linear infinite'
        }}>
          Welcome to our website predict the placements results
        </div>
      </div>

      <style>
        {`
          @keyframes marquee {
            0% { transform: translate(0, 0); }
            100% { transform: translate(-100%, 0); }
          }
        `}
      </style>

      {/* Form */}
      <div style={containerStyle}>
        <form onSubmit={handleSubmit} style={formStyle}>
          {Object.keys(form).map(key => (
            <div key={key} style={{ display: 'flex', flexDirection: 'column' }}>
              <label style={labelStyle}>{key}</label>
              <input
                name={key}
                value={form[key]}
                onChange={handleChange}
                type="number"
                step="any"
                style={inputStyle}
              />
            </div>
          ))}
          <button type="submit" style={{ ...inputStyle, cursor: 'pointer', backgroundColor: '#007bff' }}>
            Predict
          </button>
        </form>

        {/* Result */}
        {prediction && (
          <div style={prediction.prediction === 'Placed' ? resultBoxStyle : sadResultBoxStyle}>
            Student {prediction.StudentID} is {prediction.prediction === 'Placed' ? 'Placed 🙂' : 'Not Placed 🙁'}
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
